                            onClick={() => table.previousPage()}
                            disabled={!table.getCanPreviousPage()}
                            className="p-1.5 rounded-md hover:bg-neutral-700 text-neutral-400 hover:text-white disabled:opacity-40 disabled:cursor-not-allowed disabled:hover:bg-transparent disabled:hover:text-neutral-400 transition-colors"
                            title="Página anterior"
                        >
                            <CaretLeft size={16} />
                        </button>

                        <span className="px-3 py-1 text-sm text-neutral-300 min-w-[80px] text-center">
                            Página {table.getState().pagination.pageIndex + 1} de{" "}
                            {table.getPageCount()}
                        </span>

                        <button
                            type="button"
                            onClick={() => table.nextPage()}
                            disabled={!table.getCanNextPage()}
                            className="p-1.5 rounded-md hover:bg-neutral-700 text-neutral-400 hover:text-white disabled:opacity-40 disabled:cursor-not-allowed disabled:hover:bg-transparent disabled:hover:text-neutral-400 transition-colors"
                            title="Página siguiente"
                        >
                            <CaretRight size={16} />
                        </button>
                        <button
                            type="button"
                            onClick={() => table.setPageIndex(table.getPageCount() - 1)}
                            disabled={!table.getCanNextPage()}
                            className="p-1.5 rounded-md hover:bg-neutral-700 text-neutral-400 hover:text-white disabled:opacity-40 disabled:cursor-not-allowed disabled:hover:bg-transparent disabled:hover:text-neutral-400 transition-colors"
                            title="Última página"
                        >
                            <CaretDoubleRight size={16} />
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

files.features/products/queries/get-all-produc:
import { useQuery } from "@tanstack/react-query";
import { getAllProductsAction } from "../actions";
import { Product } from "@/lib/generated/prisma/browser";

export const PRODUCTS_QUERY_KEY = "products" as const;

export const useProductsQuery = () => {
    return useQuery<Product[]>({
        queryKey: [PRODUCTS_QUERY_KEY],
        queryFn: async () => {
            const result = await getAllProductsAction();
            if (result.error) {
                throw new Error(result.message);
            }
            return result.data;
        },
        staleTime: 1000 * 60 * 10,
        gcTime: 1000 * 60 * 10,
        retry: 2,
        refetchOnWindowFocus: false,
    });
};

