export const consoleLogger = (...args: unknown[]): void => {
    if (process.env.NEXT_PUBLIC_ENVIRONMENT !== "development") {
        return;
    }
    if (args.length === 0) {
        return;
    }
    try {
        console.error(...args);
    } catch (_error) {
        try {
            console.error(
                "consoleLogger failed to log arguments:",
                args,
            );
        } catch (_fallbackError) {}
    }
};

